import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { api } from "../utils/api";

function ProgressBar({ pct }) {
  const cls = pct === null ? "" : pct >= 75 ? "mint" : pct >= 50 ? "warn" : "danger";
  return (
    <div className="progress-bar">
      <div className={`progress-bar-fill ${cls}`} style={{ width: `${pct ?? 0}%` }} />
    </div>
  );
}

export default function Dashboard() {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.getDashboardStats().then(setData).finally(() => setLoading(false));
  }, []);

  if (loading) return <div className="loading">Loading…</div>;
  if (!data) return null;

  return (
    <div>
      <div className="page-header">
        <div>
          <h2>Dashboard</h2>
          <p>Overview of your discipleship class</p>
        </div>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 16, marginBottom: 32 }}>
        <div className="stat-card terra">
          <span className="stat-icon">👤</span>
          <div className="stat-value">{data.totalStudents}</div>
          <div className="stat-label">Students Enrolled</div>
        </div>
        <div className="stat-card amber">
          <span className="stat-icon">📅</span>
          <div className="stat-value">{data.totalSessions ?? 0}</div>
          <div className="stat-label">Sessions Held</div>
        </div>
        <div className="stat-card sage">
          <span className="stat-icon">📝</span>
          <div className="stat-value">{data.totalAssignments}</div>
          <div className="stat-label">Assignments</div>
        </div>
      </div>

      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div style={{ padding: "18px 24px", borderBottom: "1px solid var(--border)", display: "flex", alignItems: "center", gap: 10 }}>
          <h3 style={{ fontFamily: "var(--font-display)", fontSize: "1.3rem", fontStyle: "italic" }}>Student Progress</h3>
        </div>
        {data.students.length === 0 ? (
          <div className="empty-state">
            <div className="empty-icon">👤</div>
            <p>No students yet. Add some from the Students page.</p>
          </div>
        ) : (
          <div className="table-wrap">
            <table>
              <thead>
                <tr><th>Student</th><th>Attendance</th><th>Assignments</th><th></th></tr>
              </thead>
              <tbody>
                {data.students.map((s) => (
                  <tr key={s._id}>
                    <td style={{ fontWeight: 600 }}>{s.name}</td>
                    <td>
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <ProgressBar pct={s.attendancePct} />
                        <span style={{ fontSize: "0.8rem", color: "var(--text-muted)", minWidth: 36 }}>
                          {s.attendancePct !== null ? `${s.attendancePct}%` : "—"}
                        </span>
                      </div>
                      <div style={{ fontSize: "0.72rem", color: "var(--text-light)", marginTop: 3 }}>{s.attendanceLabel} sessions</div>
                    </td>
                    <td>
                      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                        <ProgressBar pct={s.assignmentPct} />
                        <span style={{ fontSize: "0.8rem", color: "var(--text-muted)", minWidth: 36 }}>
                          {s.assignmentPct !== null ? `${s.assignmentPct}%` : "—"}
                        </span>
                      </div>
                      <div style={{ fontSize: "0.72rem", color: "var(--text-light)", marginTop: 3 }}>{s.assignmentLabel} submitted</div>
                    </td>
                    <td>
                      <Link to={`/students/${s._id}`} className="btn btn-ghost btn-sm">View →</Link>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>
    </div>
  );
}
